import React, { useState } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';

function timeAgo(dateStr) {
  const diff = (Date.now() - new Date(dateStr)) / 1000;
  if (diff < 60) return 'just now';
  if (diff < 3600) return `${Math.floor(diff/60)}m`;
  if (diff < 86400) return `${Math.floor(diff/3600)}h`;
  return `${Math.floor(diff/86400)}d`;
}

export default function PostCard({ post, currentUser }) {
  const [liked, setLiked] = useState(post.user_liked > 0);
  const [likesCount, setLikesCount] = useState(Number(post.likes_count));
  const [comments, setComments] = useState([]);
  const [commentsCount, setCommentsCount] = useState(Number(post.comments_count));
  const [showComments, setShowComments] = useState(false);
  const [commentText, setCommentText] = useState('');
  const [heartAnim, setHeartAnim] = useState(false);

  const avatarUrl = post.avatar ? `http://localhost:5000${post.avatar}` : null;
  const postImageUrl = post.image_url ? `http://localhost:5000${post.image_url}` : null;
  const initials = (post.username || 'U')[0].toUpperCase();

  const toggleLike = async () => {
    const newLiked = !liked;
    setLiked(newLiked);
    setLikesCount(c => newLiked ? c + 1 : c - 1);
    if (newLiked) { setHeartAnim(true); setTimeout(() => setHeartAnim(false), 600); }
    try { await axios.post(`/api/posts/${post.id}/like`); }
    catch { setLiked(!newLiked); setLikesCount(c => newLiked ? c - 1 : c + 1); }
  };

  const loadComments = async () => {
    if (!showComments) {
      const { data } = await axios.get(`/api/posts/${post.id}/comments`);
      setComments(data);
    }
    setShowComments(p => !p);
  };

  const addComment = async e => {
    e.preventDefault();
    if (!commentText.trim()) return;
    try {
      const { data } = await axios.post(`/api/posts/${post.id}/comments`, { text: commentText });
      setComments(p => [...p, data]);
      setCommentsCount(c => c + 1);
      setCommentText('');
    } catch { toast.error('Failed to comment'); }
  };

  return (
    <div style={styles.card}>
      {/* Header */}
      <div style={styles.header}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          {avatarUrl
            ? <img src={avatarUrl} alt="" style={styles.avatar} />
            : <div style={{ ...styles.avatarPlaceholder }}>{initials}</div>
          }
          <div>
            <div style={{ fontWeight: 600, fontSize: 14 }}>{post.username}</div>
            <div style={{ fontSize: 12, color: '#8e8e8e' }}>{timeAgo(post.created_at)}</div>
          </div>
        </div>
        <button style={{ color: '#262626', fontSize: 20, padding: '4px 8px' }}>···</button>
      </div>

      {/* Image */}
      {postImageUrl && (
        <div style={styles.imageWrap} onDoubleClick={toggleLike}>
          <img src={postImageUrl} alt="post" style={styles.postImage} />
          {heartAnim && (
            <div style={styles.heartOverlay}>
              <svg viewBox="0 0 24 24" width="80" height="80" fill="white">
                <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
              </svg>
            </div>
          )}
        </div>
      )}

      {/* Actions */}
      <div style={styles.actions}>
        <div style={{ display: 'flex', gap: 16 }}>
          <button onClick={toggleLike} style={styles.actionBtn}>
            <svg viewBox="0 0 24 24" width="24" height="24" fill={liked ? '#ed4956' : 'none'} stroke={liked ? '#ed4956' : 'currentColor'} strokeWidth="2" style={{ transition: 'transform .1s' }}>
              <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
            </svg>
          </button>
          <button onClick={loadComments} style={styles.actionBtn}>
            <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
              <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/>
            </svg>
          </button>
          <button style={styles.actionBtn}>
            <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
            </svg>
          </button>
        </div>
        <button style={styles.actionBtn}>
          <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M19 21l-7-5-7 5V5a2 2 0 012-2h10a2 2 0 012 2z"/>
          </svg>
        </button>
      </div>

      {/* Likes */}
      <div style={styles.likesCount}>{likesCount.toLocaleString()} {likesCount === 1 ? 'like' : 'likes'}</div>

      {/* Caption */}
      {post.caption && (
        <div style={styles.caption}>
          <span style={{ fontWeight: 600 }}>{post.username}</span> {post.caption}
        </div>
      )}

      {/* Comments toggle */}
      {commentsCount > 0 && (
        <button onClick={loadComments} style={styles.viewComments}>
          {showComments ? 'Hide' : `View all ${commentsCount} comment${commentsCount !== 1 ? 's' : ''}`}
        </button>
      )}

      {/* Comments list */}
      {showComments && comments.map(c => (
        <div key={c.id} style={styles.comment}>
          <span style={{ fontWeight: 600 }}>{c.username}</span> {c.text}
        </div>
      ))}

      {/* Add comment */}
      <form onSubmit={addComment} style={styles.commentForm}>
        <svg viewBox="0 0 24 24" width="24" height="24" fill="none" stroke="#8e8e8e" strokeWidth="2" style={{ flexShrink: 0 }}>
          <circle cx="12" cy="12" r="10"/><path d="M8 14s1.5 2 4 2 4-2 4-2M9 9h.01M15 9h.01"/>
        </svg>
        <input
          value={commentText}
          onChange={e => setCommentText(e.target.value)}
          placeholder="Add a comment..."
          style={styles.commentInput}
        />
        {commentText && (
          <button type="submit" style={{ color: '#0095f6', fontWeight: 700, fontSize: 14 }}>Post</button>
        )}
      </form>
    </div>
  );
}

const styles = {
  card: { background: '#fff', border: '1px solid #dbdbdb', borderRadius: 8, marginBottom: 24, overflow: 'hidden' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '12px 16px' },
  avatar: { width: 32, height: 32, borderRadius: '50%', objectFit: 'cover' },
